import sys
sys.path.insert(0, '/testbed')
import importlib.util
spec = importlib.util.spec_from_file_location('misc', '/testbed/astropy/utils/misc.py')
misc = importlib.util.module_from_spec(spec)
spec.loader.exec_module(misc)

InheritDocstrings = misc.InheritDocstrings

# Test 1: Property with docstring inherited
class A(metaclass=InheritDocstrings):
    @property
    def foo(self):
        'The foo property'
        return 42

class B(A):
    @property
    def foo(self):
        return 43

assert B.foo.__doc__ == 'The foo property', f'Test 1 failed: {B.foo.__doc__}'
print('Test 1 passed: Property docstring inherited')

# Test 2: Property with its own docstring should not be overridden
class C(metaclass=InheritDocstrings):
    @property
    def foo(self):
        'Original doc'
        return 1

class D(C):
    @property
    def foo(self):
        'Custom doc'
        return 2

assert D.foo.__doc__ == 'Custom doc', f'Test 2 failed: {D.foo.__doc__}'
print('Test 2 passed: Property with own docstring not overridden')

# Test 3: Regular methods still work
class E(metaclass=InheritDocstrings):
    def bar(self):
        'The bar method'
        pass

class F(E):
    def bar(self):
        pass

assert F.bar.__doc__ == 'The bar method', f'Test 3 failed: {F.bar.__doc__}'
print('Test 3 passed: Regular method docstring inherited')

# Test 4: Property without docstring in parent
class G(metaclass=InheritDocstrings):
    @property
    def foo(self):
        return 1

class H(G):
    @property
    def foo(self):
        return 2

assert H.foo.__doc__ is None, f'Test 4 failed: {H.foo.__doc__}'
print('Test 4 passed: Property without parent docstring stays None')

# Test 5: Multiple inheritance
class I(metaclass=InheritDocstrings):
    @property
    def foo(self):
        'From I'
        return 1

class J(metaclass=InheritDocstrings):
    @property
    def foo(self):
        'From J'
        return 2

class K(I, J):
    @property
    def foo(self):
        return 3

assert K.foo.__doc__ == 'From I', f'Test 5 failed: {K.foo.__doc__}'
print('Test 5 passed: Multiple inheritance picks first base')

print()
print('All tests passed!')
"
"}

